import './Switch.scss';

import React from 'react';

import { classNames } from '../../helpers/classnames';
import { Typography } from '../Typography';
import type { SwitchProps } from './Switch.types';

export const Switch = React.forwardRef<HTMLInputElement, SwitchProps>(
	({ label, disabled, error = false, className, dataTestId = 'Switch', ...props }, ref) => (
		<label
			data-testid={dataTestId}
			className={classNames('dsb_switch', disabled && 'dsb_switch__disabled', error && 'dsb_switch__error', className)}
		>
			<input
				type="checkbox"
				disabled={disabled}
				aria-invalid={error}
				{...props}
				ref={ref}
				className="dsb_switch-input"
			/>
			<span className="dsb_switch-track">
				<span className="dsb_switch-slider round" />
			</span>

			{label && (
				<>
					{typeof label === 'string' ? (
						<Typography variant="body2" className="dsb_switch-label">
							{label}
						</Typography>
					) : (
						label
					)}
				</>
			)}
		</label>
	),
);
